  high: palette.surfaceContainerHigh,
  highest: palette.surfaceContainerHighest,
};

type Props = ViewProps & {
  tone?: Tone;
  level?: Level;
  rounded?: keyof typeof radius;
  style?: StyleProp<ViewStyle>;
  children?: React.ReactNode;
};

export function Surface({
  tone = 'lowest',
  level = 'level0',
