    surface: '#FFFFFF',
    surfaceContainerLow: '#FDFAF2',
    surfaceContainer: '#F1EDE2',
    onSurfaceVariant: '#5A4F33',
    outlineVariant: '#15110A',
  },
};

export const THEMES: Record<ThemeName, Theme> = {
  steadyPurple,
  bold,
};

export const DEFAULT_THEME: ThemeName = 'steadyPurple';

