/**
 * RBAC stub. Phase 1: there is no auth yet, so `useCan()` returns true for
 * everything. The shape is real, though — modules can already declare the
 * permissions they require, and screens can call `useCan()` to gate UI.
 *
 * When auth lands, replace the implementation with a real check against the
 * authenticated user's role/permission set. The contract here doesn't change.
 */

import { useCallback } from 'react';

// Permissions are namespaced strings: `<module>.<verb>` or `<module>.<resource>.<verb>`.
// Keep them short; resolve them against a real policy engine later.
export type Permission = string;

export type Role = 'guard' | 'supervisor' | 'manager' | 'admin';

export type Principal = {
  userId: string;
  roles: Role[];
  permissions: Permission[];
};

// Placeholder principal. Replace with the real signed-in user once auth lands.
export const ANONYMOUS_PRINCIPAL: Principal = {
  userId: 'anon',
  roles: ['guard'],
  permissions: ['*'],
};

export function can(principal: Principal, permission: Permission): boolean {
  if (principal.permissions.includes('*')) return true;
  return principal.permissions.includes(permission);
}

/**
 * Hook form for use in components. Returns a stable checker so callers can
 * do `const can = useCan(); can('inventory.receive')`.
 */
export function useCan() {
  return useCallback((permission: Permission) => can(ANONYMOUS_PRINCIPAL, permission), []);
}

export function useHasPermission(permission: Permission): boolean {
  return useCan()(permission);
}

