  const db = await getDb();
  return (
    (await db.getFirstAsync<OrderItem>(
      `SELECT oi.* FROM order_items oi
       JOIN orders o ON o.id = oi.order_id
       WHERE oi.barcode = ? AND o.status = 'open'
       ORDER BY o.expected_at ASC LIMIT 1`,
