import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { SectionList, StyleSheet, View } from 'react-native';
import { AppBar, Card, palette, spacing, StatusPill, Text } from '../../../design';
import { getOrderItems, listOpenOrders, Order, OrderItem } from '../../../db/orders';
import { useT } from '../../../i18n';
import { RootStackParamList } from '../../../navigation/types';

type Props = NativeStackScreenProps<RootStackParamList, 'Orders'>;
type Enriched = Order & { items: OrderItem[] };
type Bucket = 'arrived' | 'awaited' | 'done';

function bucketOf(o: Enriched): Bucket {
  if (o.items.length === 0) return 'awaited';
  const allDone = o.items.every((i) => i.received_qty >= i.expected_qty);
  if (allDone) return 'done';
  const anyReceived = o.items.some((i) => i.received_qty > 0);
  return anyReceived ? 'arrived' : 'awaited';
}

const SECTION_ORDER: Bucket[] = ['arrived', 'awaited', 'done'];

export function OrdersScreen({ navigation }: Props) {
  const t = useT();
  const [orders, setOrders] = useState<Enriched[]>([]);

  const load = useCallback(async () => {
    const list = await listOpenOrders();
    setOrders(
      await Promise.all(list.map(async (o) => ({ ...o, items: await getOrderItems(o.id) })))
    );
  }, []);

  useEffect(() => {
    load();
    const unsub = navigation.addListener('focus', load);
    return unsub;
  }, [navigation, load]);

  const sections = useMemo(() => {
    const groups: Record<Bucket, Enriched[]> = { arrived: [], awaited: [], done: [] };
    for (const o of orders) groups[bucketOf(o)].push(o);
    const titleFor: Record<Bucket, string> = {
      arrived: 'Arrived',
      awaited: t('awaited'),
      done: t('doneToday'),
    };
    return SECTION_ORDER.filter((b) => groups[b].length > 0).map((b) => ({
      title: titleFor[b],
      bucket: b,
      data: groups[b],
    }));
  }, [orders, t]);

  return (
    <View style={styles.safe}>
      <AppBar title={t('receiving')} subtitle={t('expectedToday')} onBack={() => navigation.goBack()} />
      <SectionList
        sections={sections}
        keyExtractor={(o) => o.id}
        contentContainerStyle={styles.list}
        stickySectionHeadersEnabled={false}
        renderSectionHeader={({ section }) => (
          <View style={styles.sectionHeader}>
            <Text variant="labelLarge" color={palette.onSurfaceVariant}>
              {section.title.toUpperCase()} · {section.data.length}
            </Text>
          </View>
        )}
        ItemSeparatorComponent={() => <View style={{ height: spacing.md }} />}
        SectionSeparatorComponent={() => <View style={{ height: spacing.lg }} />}
        renderItem={({ item, section }) => {
          const bucket = (section as unknown as { bucket: Bucket }).bucket;
          return (
            <Card tone="filled" padding="lg">
              <View style={styles.head}>
                <View style={{ flex: 1 }}>
                  <Text variant="titleLarge">{item.vendor ?? 'Order'}</Text>
                  {item.expected_at ? (
                    <Text variant="bodyMedium" color={palette.onSurfaceVariant} style={{ marginTop: spacing.xs }}>
                      Due {new Date(item.expected_at).toLocaleDateString()}
                    </Text>
                  ) : null}
                </View>
                <StatusPill
                  label={
                    bucket === 'done'
                      ? t('done')
                      : `${item.items.length} ${t('items')}`
                  }
                  tone={bucket === 'done' ? 'success' : bucket === 'arrived' ? 'warn' : 'neutral'}
                />
              </View>

              <View style={{ height: spacing.md }} />
              {item.items.map((i, idx) => {
                const itemDone = i.received_qty >= i.expected_qty;
                return (
                  <View
                    key={i.id}
                    style={[
                      styles.itemRow,
                      idx < item.items.length - 1 && styles.itemRowDivider,
                    ]}
                  >
                    <View style={{ flex: 1 }}>
                      <Text variant="bodyLarge" color={itemDone ? palette.onSurfaceVariant : palette.onSurface}>
                        {i.product_name}
                      </Text>
                    </View>
                    <Text
                      variant="titleMedium"
                      color={itemDone ? palette.primary : palette.onSurface}
                    >
                      {i.received_qty} / {i.expected_qty}
                    </Text>
                  </View>
                );
              })}
            </Card>
          );
        }}
        ListEmptyComponent={
          <View style={styles.empty}>
            <Text variant="headlineSmall" style={{ textAlign: 'center' }}>
              No deliveries scheduled
            </Text>
            <Text
              variant="bodyLarge"
              color={palette.onSurfaceVariant}
              style={{ textAlign: 'center', marginTop: spacing.sm }}
            >
              Orders appear here once the office processes a bill.
            </Text>
          </View>
        }
      />
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: palette.background },
  list: { padding: spacing.xl, paddingBottom: spacing.xxxl },
  sectionHeader: { paddingBottom: spacing.sm },
  head: { flexDirection: 'row', alignItems: 'flex-start', gap: spacing.md },
  itemRow: { flexDirection: 'row', alignItems: 'center', paddingVertical: spacing.sm, gap: spacing.md },
  itemRowDivider: { borderBottomWidth: 1, borderBottomColor: palette.outlineVariant },
  empty: { padding: spacing.xxl },
});

import { NativeStackScreenProps } from '@react-navigation/native-stack';
import React, { useCallback, useEffect, useState } from 'react';
import { ScrollView, StyleSheet, View } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Button, Card, palette, spacing, Text } from '../../../design';
import { listOpenOrders } from '../../../db/orders';
import { listProducts } from '../../../db/products';
import { listLowOrOut } from '../../../db/stock';
import { useT } from '../../../i18n';
import { RootStackParamList } from '../../../navigation/types';
import { QueueBadge } from '../components/QueueBadge';

type Props = NativeStackScreenProps<RootStackParamList, 'Home'>;

type Stats = {
  orders: number;
  products: number;
  alerts: number;
};

export function HomeScreen({ navigation }: Props) {
  const t = useT();
  const [stats, setStats] = useState<Stats>({ orders: 0, products: 0, alerts: 0 });

  const load = useCallback(async () => {
    const [p, o, a] = await Promise.all([listProducts(1000), listOpenOrders(), listLowOrOut()]);
    setStats({ products: p.length, orders: o.length, alerts: a.length });
  }, []);

  useEffect(() => {
    load();
    const unsub = navigation.addListener('focus', load);
    return unsub;
  }, [navigation, load]);

  return (
    <SafeAreaView edges={['top']} style={styles.safe}>
      <ScrollView contentContainerStyle={styles.scroll}>
        <View style={styles.header}>
          <Text variant="labelLarge" color={palette.onSurfaceVariant}>
            {t('guard').toUpperCase()}
          </Text>
          <Text variant="displayMedium" style={{ marginTop: spacing.xs }}>
            {t('appName')}
          </Text>
          <View style={{ marginTop: spacing.md }}>
            <QueueBadge />
          </View>
        </View>

        <View style={styles.primary}>
          <Button
            label={t('startScanning')}
            leadingIcon={<Text variant="headlineSmall" color={palette.onPrimary}>⌖</Text>}
            size="xl"
            fullWidth
            onPress={() => navigation.navigate('Scanner')}
          />
          <Text
            variant="bodyMedium"
            color={palette.onSurfaceVariant}
            style={{ textAlign: 'center', marginTop: spacing.md }}
          >
            {t('scanItem')}.
          </Text>
        </View>

        <View style={styles.tilesRow}>
          <Tile
            label={t('receiving')}
            value={stats.orders}
            sub={t('expectedToday')}
            glyph="🚚"
            onPress={() => navigation.navigate('Orders')}
          />
          <Tile
            label={t('stock')}
            value={stats.products}
            sub={t('stockSub')}
            glyph="📦"
            onPress={() => navigation.navigate('Stock')}
          />
        </View>

        <View style={styles.tilesRow}>
          <Tile
            label={t('issue')}
            sub={t('issueSub')}
            glyph="✋"
            onPress={() => navigation.navigate('Issue')}
          />
          <Tile
            label={t('alerts')}
            value={stats.alerts || undefined}
            sub={t('alertsSub')}
            glyph="🔔"
            tone={stats.alerts > 0 ? 'warn' : 'neutral'}
            onPress={() => navigation.navigate('Alerts')}
          />
        </View>

        <View style={styles.tilesRow}>
          <Tile
            label="Sync queue"
            sub="Review pending uploads"
            glyph="↻"
            onPress={() => navigation.navigate('Outbox')}
          />
          <View style={{ flex: 1 }} />
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

type TileProps = {
  label: string;
  value?: number;
  sub: string;
  glyph: string;
  tone?: 'neutral' | 'warn';
  onPress: () => void;
};

function Tile({ label, value, sub, glyph, tone = 'neutral', onPress }: TileProps) {
  return (
    <Card tone="filled" onPress={onPress} style={styles.tile}>
      <View style={styles.tileHeader}>
        <Text variant="labelLarge" color={palette.onSurfaceVariant}>
          {label.toUpperCase()}
        </Text>
        <Text variant="titleLarge">{glyph}</Text>
      </View>
      {value !== undefined ? (
        <Text
          variant="displayMedium"
          color={tone === 'warn' ? palette.error : palette.onSurface}
          style={{ marginTop: spacing.xs }}
        >
          {value}
        </Text>
      ) : (
        <View style={{ height: spacing.md }} />
      )}
      <Text variant="bodyMedium" color={palette.onSurfaceVariant}>
        {sub}
      </Text>
    </Card>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: palette.background },
  scroll: { paddingBottom: spacing.xxxl },
  header: { paddingHorizontal: spacing.xl, paddingTop: spacing.lg, paddingBottom: spacing.xl },
  primary: {
    paddingHorizontal: spacing.xl,
    paddingTop: spacing.md,
    paddingBottom: spacing.xxl,
  },
  tilesRow: {
    flexDirection: 'row',
    gap: spacing.md,
    paddingHorizontal: spacing.xl,
    marginBottom: spacing.md,
  },
  tile: { flex: 1 },
  tileHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' },
});

