# System Plugins

This folder is the backend extension boundary for product-like systems that live inside `appointy-ops` without becoming part of the core runtime.

## Why this exists

- Keep shared infrastructure in `core/`, `channels/`, and Mastra registration.
- Keep bounded business logic in a plugin-owned surface.
- Make it easy to extract a system later without rewriting the whole app.
- Give future systems like visitor, inventory, or asset operations one obvious home.

## Current pattern

Each plugin gets:

- A registry entry in `src/mastra/plugins/index.ts`
- A plugin definition implementing `OfficeOpsPlugin`
- A single import surface like `src/mastra/plugins/visitor/index.ts`
- Ownership of its own HTTP routes, background jobs, and business helpers

Core code should import plugin functionality from `src/mastra/plugins/<plugin>` instead of reaching into internal module paths.

## Recommended shape for future systems

```text
src/mastra/plugins/
  inventory/
    index.ts
    plugin.ts
    ...
  visitor/
    index.ts
    plugin.ts
    ...
```

If a system also has its own frontend, keep that frontend in a separate client repository:

```text
appointy-visitor-web/
appointy-ops-dashboard/
```

That lets this repository stay focused on backend APIs, orchestration, plugins, channels, and data.
---registry---
import type { IncomingMessage, ServerResponse } from "http";
import type { OfficeOpsPlugin } from "./types";

const plugins = new Map<string, OfficeOpsPlugin>();

export function registerPlugin(plugin: OfficeOpsPlugin): void {
  if (plugins.has(plugin.id)) {
    console.warn(`⚠️ [PluginRegistry] Overwriting existing plugin: ${plugin.id}`);
  }

  plugins.set(plugin.id, plugin);
  console.log(`🧩 [PluginRegistry] Registered plugin: ${plugin.id} (${plugin.name})`);
}

export function getPlugin(id: string): OfficeOpsPlugin | undefined {
  return plugins.get(id);
}

export function getAllPlugins(): OfficeOpsPlugin[] {
  return Array.from(plugins.values());
}

export async function initPlugins(): Promise<void> {
  for (const plugin of plugins.values()) {
    if (plugin.init) {
      await plugin.init();
    }
  }
}

export function startPluginBackgroundJobs(): void {
  for (const plugin of plugins.values()) {
    plugin.startBackgroundJobs?.();
  }
}

export async function handlePluginHttpRequest(
  req: IncomingMessage,
  res: ServerResponse,
): Promise<boolean> {
  for (const plugin of plugins.values()) {
    if (!plugin.handleHttpRequest) continue;

    const handled = await plugin.handleHttpRequest(req, res);
    if (handled) return true;
  }

  return false;
}
---types---
import type { IncomingMessage, ServerResponse } from "http";

export interface OfficeOpsPlugin {
  id: string;
  name: string;
  init?: () => Promise<void>;
  handleHttpRequest?: (
    req: IncomingMessage,
    res: ServerResponse,
  ) => Promise<boolean>;
  startBackgroundJobs?: () => void;
}

