---visitor plugin.ts---
import { logError, logInfo } from "../../lib/logger";
import { checkOverstays } from "../../modules/visitor/overstay-monitor";
import {
  handleVisitorRequest,
  initVisitorModule,
} from "../../modules/visitor/index";
import type { OfficeOpsPlugin } from "../types";

const OVERSTAY_INTERVAL_MS = 30 * 60 * 1000;
const OVERSTAY_INITIAL_DELAY_MS = 5 * 60 * 1000;

let backgroundJobsStarted = false;

async function runVisitorOverstayCheck(): Promise<void> {
  try {
    await checkOverstays();
  } catch (error) {
    logError("[VisitorPlugin] Overstay check failed", error, {
      scope: "visitor-plugin",
      job: "overstay-check",
    });
  }
}

export const visitorPlugin: OfficeOpsPlugin = {
  id: "visitor",
  name: "Visitor Management",

  async init(): Promise<void> {
    await initVisitorModule();
  },

  async handleHttpRequest(req, res): Promise<boolean> {
    return handleVisitorRequest(req, res);
  },

  startBackgroundJobs(): void {
    if (backgroundJobsStarted) return;
    backgroundJobsStarted = true;

    setInterval(() => {
      void runVisitorOverstayCheck();
    }, OVERSTAY_INTERVAL_MS);

    setTimeout(() => {
      void runVisitorOverstayCheck();
    }, OVERSTAY_INITIAL_DELAY_MS);

    logInfo("Visitor overstay check scheduled every 30 minutes", {
      scope: "visitor-plugin",
      job: "overstay-check",
    });
  },
};

