 * 
 * Central hub registering all agents, workflows, tools, and infrastructure.
 * This is the backbone of the entire system.
 */

import { Mastra } from '@mastra/core/mastra';
import { PinoLogger } from '@mastra/loggers';
import { PostgresStore } from '@mastra/pg';
import { normalizePostgresConnectionString } from './lib/postgres';

// ─── Graph node-type registration (must run before any request) ───
import { registerDefaultFlowPacks } from './modules/flow-packs';
registerDefaultFlowPacks();

// ─── Agents ───────────────────────────────────────────────
import { routerAgent } from './agents/router-agent';
import { visitorAgent } from './agents/visitor-agent';
import { inventoryAgent } from './agents/inventory-agent';
import { assetAgent } from './agents/asset-agent';
import { facilityAgent } from './agents/facility-agent';
import { queryAgent } from './agents/query-agent';
import { configAgent } from './agents/config-agent';

// ─── Workflows ────────────────────────────────────────────
