import { dailySummaryWorkflow } from './workflows/daily-summary';
import { overdueCheckWorkflow } from './workflows/overdue-check';
import {
  ticketNotifyWorkflow,
  ticketProgressWorkflow,
  ticketDoneWorkflow,
} from './workflows/ticket-lifecycle';

// ─── Mastra Instance ─────────────────────────────────────

export const mastra = new Mastra({
  agents: {
    routerAgent,
    visitorAgent,
    inventoryAgent,
    assetAgent,
    facilityAgent,
    queryAgent,
    configAgent,
  },
  workflows: {
    ingestMessageWorkflow,
    dailySummaryWorkflow,
    overdueCheckWorkflow,
    ticketNotifyWorkflow,
    ticketProgressWorkflow,
    ticketDoneWorkflow,
  },
  storage: new PostgresStore({
    id: 'mastra-storage',
    connectionString: normalizePostgresConnectionString(
      process.env.DATABASE_URL ?? (() => {
        throw new Error('DATABASE_URL is required for Mastra Postgres storage.');
      })(),
    ),
    schemaName: process.env.TOOL_SCHEMA ?? 'appointy_ops',
  }),
  logger: new PinoLogger({
    name: 'OfficeOps',
    level: 'info',
  }),
});

