// ─── Inventory Tools ──────────────────────────────────────

export const saveInventoryDbTool = createTool({
  id: "save-inventory",
  description: "Save an inventory/kitchen/pantry record to the database.",
  inputSchema: z.object({
    item: z.string().describe("Name of the item"),
    quantity: z
      .string()
      .nullable()
      .optional()
      .describe('Quantity with unit, e.g. "20 litre", "50 packets"'),
    action: z
      .enum(["ordered", "received", "consumed", "restocked", "unknown"])
      .describe("What happened"),
    vendor: z.string().nullable().optional().describe("Vendor/supplier name"),
    cost: z.number().nullable().optional().describe("Cost in rupees"),
    mismatchFlag: z
      .boolean()
      .describe("True if there is a quantity discrepancy"),
    confidence: z.number().min(0).max(1).describe("Extraction confidence"),
    sourceQuote: z
      .string()
      .describe(
        "The EXACT words from the original message that justify your extraction. Copy-paste from the source, do not rephrase.",
      ),
    sourceMessageId: z.string().describe("ID of the raw message"),
    telegramMsgId: z
      .number()
      .nullable()
      .optional()
      .describe("Telegram message ID for deep-linking"),
    telegramChatId: z
      .number()
      .nullable()
      .optional()
      .describe("Telegram chat ID for deep-linking"),
  }),
  outputSchema: z.object({
    success: z.boolean(),
    recordId: z.string(),
    message: z.string(),
  }),
  execute: async (input) => {
    try {
      const recordId = await saveInventory({
        item: input.item,
        quantity: input.quantity,
        action: input.action,
        vendor: input.vendor,
        cost: input.cost,
        mismatchFlag: input.mismatchFlag,
        confidence: input.confidence,
