/**
 * Visitor Module — Database Layer
 *
 * All SQL queries for visitor_invitations, visitor_sessions,
 * visitor_audit_log, guards, and visitor_locations.
 * Schema migration is handled by the shared Neon/Postgres bootstrap.
 */

import { randomUUID } from 'crypto';
import { getDb } from '../../lib/database';
import { ensureOfficeOpsPostgresSchema, isPostgresConfigured } from '../../lib/postgres';
import { formatDateInIST } from '../../lib/time';
import type {
  Guard,
  GuardSessionRecord,
  VisitorInvitation,
  VisitorManagementQueryRecord,
  VisitorSession,
  VisitorLocation,
  CreateInvitationInput,
  HostResponse,
  OfflineEventType,
  OfflineSyncEvent,
  OfflineSyncRecord,
  OfflineSyncStatus,
  VisitorApprovalStatus,
} from './types';

// ─── Schema Initialization ────────────────────────────────────

type InValue = string | number | boolean | null | Uint8Array | Date;

export async function initVisitorSchema(): Promise<void> {
  if (!isPostgresConfigured()) {
    throw new Error('DATABASE_URL is required. Visitor local database initialization has been removed.');
  }

  await ensureOfficeOpsPostgresSchema();
  console.log('✅ [VisitorModule] Neon/Postgres schema initialized');
}

// ─── Guards ───────────────────────────────────────────────────

export async function createGuard(data: {
  name: string;
  pinHash: string;
  phone?: string;
  language?: 'hindi' | 'english';
}): Promise<string> {
  const db = await getDb();
  const id = randomUUID();
  await db.execute({
    sql: `INSERT INTO guards (id, name, pin_hash, phone, language) VALUES (?, ?, ?, ?, ?)`,
    args: [id, data.name, data.pinHash, data.phone ?? null, data.language ?? 'hindi'],
  });
  return id;
}

export async function findGuardByName(name: string): Promise<Guard | null> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM guards WHERE name = ? AND is_active = 1 LIMIT 1`,
    args: [name],
  });
  return (result.rows[0] as unknown as Guard) ?? null;
}

export async function getAllActiveGuards(): Promise<Guard[]> {
