import { drizzle, type NodePgDatabase } from "drizzle-orm/node-postgres";
import { Pool } from "pg";
import * as schema from "../db/schema";
import { officeOpsSchemaName, officeOpsSchemaSql, quoteIdentifier } from "./postgres-schema";

let pool: Pool | null = null;
let db: NodePgDatabase<typeof schema> | null = null;
let schemaReady: Promise<void> | null = null;

export function normalizePostgresConnectionString(connectionString: string): string {
  const url = new URL(connectionString);
  const sslMode = url.searchParams.get("sslmode");
  if (!sslMode && url.hostname.includes("neon.tech")) {
    url.searchParams.set("sslmode", "verify-full");
    return url.toString();
  }
  if (sslMode && ["prefer", "require", "verify-ca"].includes(sslMode)) {
    url.searchParams.set("sslmode", "verify-full");
    return url.toString();
  }
  return connectionString;
}

export function isPostgresConfigured(): boolean {
  return Boolean(process.env.DATABASE_URL);
}

export function getPostgresDb(): NodePgDatabase<typeof schema> {
  if (db) return db;

  db = drizzle(getPostgresPool(), { schema });
  return db;
}

export function getPostgresPool(): Pool {
  if (pool) return pool;

  const connectionString = process.env.DATABASE_URL;
  if (!connectionString) {
    throw new Error("DATABASE_URL is not configured");
  }

  pool = new Pool({
    connectionString: normalizePostgresConnectionString(connectionString),
    keepAlive: true,
    idleTimeoutMillis: 10000,
    connectionTimeoutMillis: 5000,
  });

  pool.on("connect", (client) => {
    client.query(`SET search_path TO ${officeOpsSchemaName()},public`).catch((err) => {
      console.error("[postgres] Error setting search_path:", err.message);
    });
  });

  // Prevent unhandled 'error' events from crashing the process when Neon
  // terminates idle connections — pg-pool emits on the pool, not the caller.
  pool.on("error", (err) => {
    console.error("[postgres] Idle client error (connection terminated):", err.message);
  });

  return pool;
}

export function getOptionalPostgresDb(): NodePgDatabase<typeof schema> | null {
  if (!isPostgresConfigured()) return null;
  return getPostgresDb();
}

export async function closePostgresDb(): Promise<void> {
  await pool?.end();
  pool = null;
  db = null;
  schemaReady = null;
}

export async function ensureOfficeOpsPostgresSchema(): Promise<void> {
  if (!isPostgresConfigured()) {
    throw new Error("DATABASE_URL is not configured");
  }

