] as const;

export async function getDb(): Promise<Client> {
  if (_db) return _db;

  if (!isPostgresConfigured()) {
    throw new Error("DATABASE_URL is required. Office Ops now uses Neon/Postgres only.");
  }

  await ensureOfficeOpsPostgresSchema();
  _db = createPostgresCompatClient();
  return _db;
}

export async function resetDatabase(): Promise<{
  clearedTables: readonly string[];
}> {
  const db = await getDb();
  await db.batch(
    RESET_TABLES_IN_ORDER.map((table) => `DELETE FROM ${table}`),
    "write",
  );

  return {
    clearedTables: RESET_TABLES_IN_ORDER,
  };
}

function createPostgresCompatClient(): Client {
  return {
    async execute(statement: SqlStatement): Promise<SqlResult> {
      const normalized = normalizePostgresStatement(statement);
      if (!normalized.sql.trim()) return { rows: [], rowsAffected: 0 };
      const result = await getPostgresPool().query(normalized.sql, normalized.args);
      return {
        rows: result.rows,
        rowsAffected: result.rowCount ?? 0,
      };
    },
    async executeMultiple(sql: string): Promise<void> {
      for (const statement of splitSqlStatements(sql)) {
        const normalized = normalizePostgresStatement(statement);
        if (normalized.sql.trim()) {
          await getPostgresPool().query(normalized.sql, normalized.args);
        }
      }
    },
    async batch(statements: readonly SqlStatement[]): Promise<SqlResult[]> {
      const client = await getPostgresPool().connect();
      try {
        await client.query("BEGIN");
        const results: SqlResult[] = [];
        for (const statement of statements) {
          const normalized = normalizePostgresStatement(statement);
          if (!normalized.sql.trim()) {
            results.push({ rows: [], rowsAffected: 0 });
            continue;
          }
          const result = await client.query(normalized.sql, normalized.args);
          results.push({ rows: result.rows, rowsAffected: result.rowCount ?? 0 });
        }
        await client.query("COMMIT");
        return results;
      } catch (error) {
        await client.query("ROLLBACK");
        throw error;
      } finally {
        client.release();
      }
    },
  };
}

function normalizePostgresStatement(statement: SqlStatement): { sql: string; args: SqlArgs } {
  const rawSql = typeof statement === "string" ? statement : statement.sql;
  const args = typeof statement === "string" ? [] : statement.args ?? [];
  let sql = rawSql.trim();

  if (!sql) {
    return { sql: "", args };
