function replaceQuestionPlaceholders(sql: string): string {
  let index = 0;
  let output = "";
  let inSingleQuote = false;
  for (let i = 0; i < sql.length; i++) {
    const char = sql[i];
    const next = sql[i + 1];
    if (char === "'" && next === "'") {
      output += char + next;
      i++;
      continue;
    }
    if (char === "'") {
      inSingleQuote = !inSingleQuote;
      output += char;
      continue;
    }
    if (char === "?" && !inSingleQuote) {
      index++;
      output += `$${index}`;
      continue;
    }
    output += char;
  }
  return output;
}

