import { dispatchFlowEmails, dispatchFlowNotifications, readFlowSideEffects, runFlowRules } from '../../lib/flow';
import { executeVisitorBroadcast } from './visitor-broadcast';

// ─── Helpers ──────────────────────────────────────────────────

function json(res: ServerResponse, status: number, data: unknown): void {
  const body = JSON.stringify(data);
  res.writeHead(status, {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET,POST,PUT,PATCH,DELETE,OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type,Accept,Authorization,x-admin-secret,x-actor-name,x-actor-email,x-actor-role,x-guard-token,x-invited-by,x-email-template-key,x-pass-template-key',
  });
  res.end(body);
}


async function getActiveBroadcastForInvitation(invitationId: string): Promise<{
  id: string;
  message: string;
  createdAt: string;
} | null> {
  const db = getOptionalPostgresDb();
  if (!db) return null;

  const { getSessionByInvitation } = await import("./db");
  const session = await getSessionByInvitation(invitationId);
  if (!session?.checkin_time) return null;

  try {
    const rows = await db
      .select()
      .from(visitorBroadcasts)
      .where(eq(visitorBroadcasts.status, "active"))
      .orderBy(desc(visitorBroadcasts.createdAt))
      .limit(10);

    const checkinAt = new Date(session.checkin_time).getTime();
    const now = Date.now();
    const active = rows.find((row) => {
      const createdAt = row.createdAt ? new Date(row.createdAt).getTime() : 0;
      const expiresAt = row.expiresAt ? new Date(row.expiresAt).getTime() : null;
      return createdAt >= checkinAt && (expiresAt == null || expiresAt > now);
    });

    return active ? {
      id: active.id,
      message: active.message,
      createdAt: active.createdAt?.toISOString?.() ?? String(active.createdAt),
    } : null;
  } catch {
    return null;
  }
}

function corsPreflight(res: ServerResponse): void {
  res.writeHead(204, {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET,POST,PUT,PATCH,DELETE,OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type,Accept,Authorization,x-admin-secret,x-actor-name,x-actor-email,x-actor-role,x-guard-token,x-invited-by,x-email-template-key,x-pass-template-key',
    'Access-Control-Max-Age': '86400',
  });
  res.end();
}

async function readBody(req: IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    let data = '';
    req.on('data', (chunk) => { data += chunk; });
    req.on('end', () => resolve(data));
    req.on('error', reject);
  });
}

async function readBodyJson(req: IncomingMessage): Promise<Record<string, unknown>> {
  const raw = await readBody(req);
  try { return JSON.parse(raw); } catch { return {}; }
}

async function guardAuth(req: IncomingMessage): Promise<Awaited<ReturnType<typeof validateGuardSession>>> {
  const token = req.headers['x-guard-token'] as string | undefined
    ?? parseUrl(req.url ?? '', true).query['token'] as string | undefined;
  if (!token) return null;
  return validateGuardSession(token);
}

