/**
 * Inventory Plugin — Database Layer
 *
 * SQL surface backing the field-app gate-entry flow. Distinct from the
 * legacy top-level `inventory` table, which stores LLM extractions from
 * chat messages — these tables persist the structured capture stream
 * (products, orders, receipts, stock, issues, reorder requests,
 * mismatch flags).
 *
 * Schema migration runs from `lib/postgres-schema.ts` via
 * `ensureOfficeOpsPostgresSchema()`, the same boot path the visitor
 * module uses. This file owns the CRUD only.
 */

import { getDb } from "../../lib/database";
import { ensureOfficeOpsPostgresSchema } from "../../lib/postgres";

export type InventoryProduct = {
  barcode: string;
  site_id: string;
  name: string;
  category: string | null;
  unit: string | null;
  registered_by: string | null;
  created_at: string;
  updated_at: string;
};

export type InventoryOrder = {
  id: string;
  site_id: string;
  vendor: string | null;
  expected_at: string | null;
  arrived_at: string | null;
  status: string;
  created_at: string;
  updated_at: string;
};

export type InventoryOrderItem = {
  id: string;
  order_id: string;
  barcode: string | null;
  product_name: string;
  expected_qty: number;
  received_qty: number;
};

export type InventoryStockRow = {
  barcode: string;
  site_id: string;
  name: string;
  category: string | null;
  unit: string | null;
  on_hand: number;
  threshold: number;
  updated_at: string;
};

export type InventoryReceipt = {
  id: string;
  site_id: string;
  order_id: string | null;
  order_item_id: string | null;
  barcode: string;
  product_name: string;
  qty: number;
  flagged: boolean;
  device_id: string | null;
  guard_id: string | null;
  scanned_at: string;
};

export async function initInventorySchema(): Promise<void> {
  await ensureOfficeOpsPostgresSchema();
}

// ─── Products ─────────────────────────────────────────────────────

export async function upsertProduct(input: {
  siteId: string;
  barcode: string;
  name: string;
  category?: string | null;
  unit?: string | null;
  registeredBy?: string | null;
}): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `
      INSERT INTO inventory_products (barcode, site_id, name, category, unit, registered_by)
      VALUES (?, ?, ?, ?, ?, ?)
      ON CONFLICT (site_id, barcode) DO UPDATE SET
        name = EXCLUDED.name,
        category = COALESCE(EXCLUDED.category, inventory_products.category),
        unit = COALESCE(EXCLUDED.unit, inventory_products.unit),
        updated_at = now()
    `,
    args: [
      input.barcode,
      input.siteId,
      input.name,
      input.category ?? null,
      input.unit ?? null,
      input.registeredBy ?? null,
    ],
  });
}

export async function findProduct(
  siteId: string,
  barcode: string,
): Promise<InventoryProduct | null> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM inventory_products WHERE site_id = ? AND barcode = ? LIMIT 1`,
    args: [siteId, barcode],
  });
  return (result.rows[0] as InventoryProduct | undefined) ?? null;
}

// ─── Orders ───────────────────────────────────────────────────────

export async function listOpenOrders(siteId: string): Promise<InventoryOrder[]> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM inventory_orders WHERE site_id = ? AND status = 'open' ORDER BY expected_at ASC NULLS LAST`,
    args: [siteId],
  });
  return result.rows as InventoryOrder[];
}

export async function getOrderItems(orderId: string): Promise<InventoryOrderItem[]> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM inventory_order_items WHERE order_id = ?`,
    args: [orderId],
  });
  return result.rows as InventoryOrderItem[];
}

export async function findOpenItemByBarcode(
  siteId: string,
  barcode: string,
): Promise<InventoryOrderItem | null> {
  const db = await getDb();
  const result = await db.execute({
    sql: `
      SELECT oi.* FROM inventory_order_items oi
      JOIN inventory_orders o ON o.id = oi.order_id
      WHERE oi.barcode = ? AND o.site_id = ? AND o.status = 'open'
      ORDER BY o.expected_at ASC NULLS LAST
      LIMIT 1
    `,
    args: [barcode, siteId],
  });
  return (result.rows[0] as InventoryOrderItem | undefined) ?? null;
}

export async function addReceivedQty(itemId: string, delta: number): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `UPDATE inventory_order_items SET received_qty = received_qty + ? WHERE id = ?`,
    args: [delta, itemId],
  });
}

export async function markOrderArrived(orderId: string, when: string): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `UPDATE inventory_orders SET arrived_at = ?, updated_at = now() WHERE id = ? AND arrived_at IS NULL`,
    args: [when, orderId],
  });
}

// ─── Receipts ─────────────────────────────────────────────────────

/**
 * Idempotent on `id`. Field-app outbox retries land here without
 * double-counting because we ON CONFLICT DO NOTHING and report whether
 * the row was actually inserted.
 */
export async function insertReceipt(input: {
  id: string;
  siteId: string;
  orderId?: string | null;
  orderItemId?: string | null;
  barcode: string;
  productName: string;
  qty: number;
  flagged?: boolean;
  deviceId?: string | null;
  guardId?: string | null;
  scannedAt: string;
}): Promise<{ inserted: boolean }> {
  const db = await getDb();
  const result = await db.execute({
    sql: `
      INSERT INTO inventory_receipts (
        id, site_id, order_id, order_item_id, barcode, product_name,
        qty, flagged, device_id, guard_id, scanned_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT (id) DO NOTHING
    `,
    args: [
      input.id,
      input.siteId,
      input.orderId ?? null,
      input.orderItemId ?? null,
      input.barcode,
      input.productName,
      input.qty,
      input.flagged ?? false,
      input.deviceId ?? null,
      input.guardId ?? null,
      input.scannedAt,
    ],
  });
  return { inserted: (result.rowsAffected ?? 0) > 0 };
}

// ─── Stock ────────────────────────────────────────────────────────

export async function listStock(siteId: string): Promise<InventoryStockRow[]> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM inventory_stock WHERE site_id = ? ORDER BY name`,
    args: [siteId],
  });
  return result.rows as InventoryStockRow[];
}

export async function listLowOrOut(siteId: string): Promise<InventoryStockRow[]> {
  const db = await getDb();
  const result = await db.execute({
    sql: `
      SELECT * FROM inventory_stock
      WHERE site_id = ? AND on_hand <= threshold
      ORDER BY on_hand ASC, name ASC
    `,
    args: [siteId],
  });
  return result.rows as InventoryStockRow[];
}

export async function findStock(
  siteId: string,
  barcode: string,
): Promise<InventoryStockRow | null> {
  const db = await getDb();
  const result = await db.execute({
    sql: `SELECT * FROM inventory_stock WHERE site_id = ? AND barcode = ? LIMIT 1`,
    args: [siteId, barcode],
  });
  return (result.rows[0] as InventoryStockRow | undefined) ?? null;
}

export async function upsertStock(input: {
  siteId: string;
  barcode: string;
  name: string;
  category?: string | null;
  unit?: string | null;
  onHand?: number;
  threshold?: number;
}): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `
      INSERT INTO inventory_stock (
        barcode, site_id, name, category, unit, on_hand, threshold
      )
      VALUES (?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT (site_id, barcode) DO UPDATE SET
        name = EXCLUDED.name,
        category = COALESCE(EXCLUDED.category, inventory_stock.category),
        unit = COALESCE(EXCLUDED.unit, inventory_stock.unit),
        updated_at = now()
    `,
    args: [
      input.barcode,
      input.siteId,
      input.name,
      input.category ?? null,
      input.unit ?? null,
      input.onHand ?? 0,
      input.threshold ?? 0,
    ],
  });
}

/**
 * Apply a quantity delta to the on-hand level. Creates the row from the
 * receipt's product info if it doesn't yet exist, so the field-app's
 * Stock screen surfaces new SKUs as soon as they're scanned.
 */
export async function adjustOnHand(input: {
  siteId: string;
  barcode: string;
  delta: number;
  fallbackName?: string;
  fallbackCategory?: string | null;
  fallbackUnit?: string | null;
}): Promise<void> {
  const db = await getDb();
  await db.execute({
    sql: `
      INSERT INTO inventory_stock (barcode, site_id, name, category, unit, on_hand, threshold)
      VALUES (?, ?, ?, ?, ?, GREATEST(?, 0), 0)
      ON CONFLICT (site_id, barcode) DO UPDATE SET
        on_hand = GREATEST(inventory_stock.on_hand + EXCLUDED.on_hand, 0),
        updated_at = now()
    `,
    args: [
      input.barcode,
      input.siteId,
      input.fallbackName ?? "Unknown",
      input.fallbackCategory ?? null,
      input.fallbackUnit ?? null,
      input.delta,
    ],
  });
}

// ─── Issues / Reorders / Mismatches ──────────────────────────────

export async function insertIssue(input: {
  id: string;
  siteId: string;
  barcode: string;
  productName: string;
  qty: number;
  reason?: string | null;
  takenBy?: string | null;
  deviceId?: string | null;
  guardId?: string | null;
  issuedAt: string;
}): Promise<{ inserted: boolean }> {
  const db = await getDb();
  const result = await db.execute({
    sql: `
      INSERT INTO inventory_issues (
        id, site_id, barcode, product_name, qty, reason, taken_by,
        device_id, guard_id, issued_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT (id) DO NOTHING
    `,
    args: [
      input.id,
      input.siteId,
      input.barcode,
      input.productName,
      input.qty,
      input.reason ?? null,
      input.takenBy ?? null,
      input.deviceId ?? null,
      input.guardId ?? null,
      input.issuedAt,
    ],
  });
  return { inserted: (result.rowsAffected ?? 0) > 0 };
}

export async function insertReorderRequest(input: {
  id: string;
  siteId: string;
  barcode: string;
  productName: string;
  onHand?: number | null;
  threshold?: number | null;
  requestedBy?: string | null;
  deviceId?: string | null;
  guardId?: string | null;
  requestedAt: string;
}): Promise<{ inserted: boolean }> {
  const db = await getDb();
  const result = await db.execute({
    sql: `
      INSERT INTO inventory_reorder_requests (
        id, site_id, barcode, product_name, on_hand, threshold,
        requested_by, device_id, guard_id, status, requested_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'open', ?)
      ON CONFLICT (id) DO NOTHING
    `,
    args: [
      input.id,
      input.siteId,
      input.barcode,
      input.productName,
      input.onHand ?? null,
      input.threshold ?? null,
      input.requestedBy ?? null,
      input.deviceId ?? null,
      input.guardId ?? null,
      input.requestedAt,
    ],
  });
  return { inserted: (result.rowsAffected ?? 0) > 0 };
}

export async function insertMismatchFlag(input: {
  id: string;
  siteId: string;
  receiptId?: string | null;
  orderItemId?: string | null;
  barcode: string;
  expected?: number | null;
  receivedTotal?: number | null;
  note?: string | null;
  deviceId?: string | null;
  guardId?: string | null;
  flaggedAt: string;
}): Promise<{ inserted: boolean }> {
  const db = await getDb();
  const result = await db.execute({
    sql: `
      INSERT INTO inventory_mismatch_flags (
        id, site_id, receipt_id, order_item_id, barcode, expected,
        received_total, note, device_id, guard_id, flagged_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT (id) DO NOTHING
    `,
    args: [
      input.id,
      input.siteId,
      input.receiptId ?? null,
      input.orderItemId ?? null,
      input.barcode,
      input.expected ?? null,
      input.receivedTotal ?? null,
      input.note ?? null,
      input.deviceId ?? null,
      input.guardId ?? null,
      input.flaggedAt,
    ],
  });
  return { inserted: (result.rowsAffected ?? 0) > 0 };
}

input.content:
/**
 * Inventory Plugin — HTTP Routes
 *
 * Field-app facing surface under /api/inventory/*.
 *
 * Writes (idempotent on `id`):
 *   POST /api/inventory/receipts          — gate capture
 *   POST /api/inventory/products          — catalog upsert (register barcode)
 *   POST /api/inventory/issues            — consumption
 *   POST /api/inventory/reorder-requests  — low-stock reorder ask
 *   POST /api/inventory/mismatch-flags    — receipt mismatch report
 *
 * Reads (guard-authenticated):
 *   GET  /api/inventory/orders            — open orders + items
 *   GET  /api/inventory/stock             — all stock rows
 *   GET  /api/inventory/alerts            — low + out of stock
 *   GET  /api/inventory/catalog/:barcode  — product lookup
 *
 * Auth: reuses the visitor module's guard session token. The field-app
 * obtains it via POST /api/guard/login (visitor routes) and sends it as
 * the `x-guard-token` header. Site selection is done with the
 * `x-site-id` header (defaults to the guard's session site when added).
 */

import type { IncomingMessage, ServerResponse } from "http";
import { parse as parseUrl } from "url";

import { logError } from "../../lib/logger";
import { validateGuardSession } from "../visitor/guard-auth";
import {
  addReceivedQty,
  adjustOnHand,
  findOpenItemByBarcode,
  findProduct,
  getOrderItems,
  insertIssue,
  insertMismatchFlag,
  insertReceipt,
  insertReorderRequest,
  listLowOrOut,
  listOpenOrders,
  listStock,
  upsertProduct,
  upsertStock,
} from "./db";

// ─── Helpers ─────────────────────────────────────────────────────

const CORS_HEADERS = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET,POST,PUT,PATCH,DELETE,OPTIONS",
  "Access-Control-Allow-Headers":
    "Content-Type,Accept,Authorization,x-guard-token,x-site-id,x-device-id",
};

function json(res: ServerResponse, status: number, data: unknown): void {
  res.writeHead(status, { "Content-Type": "application/json", ...CORS_HEADERS });
  res.end(JSON.stringify(data));
}

function corsPreflight(res: ServerResponse): void {
  res.writeHead(204, { ...CORS_HEADERS, "Access-Control-Max-Age": "86400" });
  res.end();
}

async function readBodyJson(req: IncomingMessage): Promise<Record<string, unknown>> {
  return new Promise((resolve, reject) => {
    let raw = "";
    req.on("data", (chunk) => {
      raw += chunk;
    });
    req.on("end", () => {
      try {
        resolve(raw ? JSON.parse(raw) : {});
      } catch {
        resolve({});
      }
    });
    req.on("error", reject);
  });
}

function header(req: IncomingMessage, name: string): string | undefined {
  const v = req.headers[name];
  return Array.isArray(v) ? v[0] : v;
}

type AuthedRequest = {
  guardId: string;
  guardName: string;
  siteId: string;
  deviceId: string | null;
};

async function authenticate(
  req: IncomingMessage,
  res: ServerResponse,
): Promise<AuthedRequest | null> {
  const token =
    header(req, "x-guard-token") ??
    (parseUrl(req.url ?? "", true).query["token"] as string | undefined);
  if (!token) {
    json(res, 401, { error: "Missing x-guard-token" });
    return null;
  }
  const session = await validateGuardSession(token);
  if (!session) {
    json(res, 401, { error: "Invalid or expired session" });
    return null;
  }
  const siteId = header(req, "x-site-id");
  if (!siteId) {
    json(res, 400, { error: "Missing x-site-id" });
    return null;
  }
  return {
    guardId: session.guardId,
    guardName: session.guardName,
    siteId,
    deviceId: header(req, "x-device-id") ?? null,
  };
}

function asString(v: unknown): string | null {
  if (typeof v !== "string") return null;
  const t = v.trim();
  return t.length === 0 ? null : t;
}

function asNumber(v: unknown): number | null {
  if (typeof v === "number" && Number.isFinite(v)) return v;
  if (typeof v === "string") {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  }
  return null;
}

function asBool(v: unknown): boolean {
  return v === true || v === "true" || v === 1;
}

function isoOrNow(v: unknown): string {
  if (typeof v === "number") return new Date(v).toISOString();
  if (typeof v === "string") {
    const t = Date.parse(v);
    if (!Number.isNaN(t)) return new Date(t).toISOString();
  }
  return new Date().toISOString();
}

// ─── Route Matcher ───────────────────────────────────────────────

export async function handleInventoryRequest(
  req: IncomingMessage,
  res: ServerResponse,
): Promise<boolean> {
  const { pathname } = parseUrl(req.url ?? "", true);
  const method = req.method?.toUpperCase() ?? "GET";

  if (!pathname || !pathname.startsWith("/api/inventory/")) return false;

  if (method === "OPTIONS") {
    corsPreflight(res);
    return true;
  }

  try {
    return await dispatch(req, res, pathname, method);
  } catch (error) {
    logError("[InventoryRoutes] Unhandled error", error, {
      scope: "inventory-plugin",
      pathname,
      method,
    });
    json(res, 500, { error: "Internal error" });
    return true;
  }
}

async function dispatch(
  req: IncomingMessage,
  res: ServerResponse,
  pathname: string,
  method: string,
): Promise<boolean> {
  // ── Writes ────────────────────────────────────────────────

  if (pathname === "/api/inventory/receipts" && method === "POST") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    const body = await readBodyJson(req);

    const id = asString(body.id);
    const barcode = asString(body.barcode);
    const qty = asNumber(body.qty);
    if (!id || !barcode || qty === null) {
      json(res, 400, { error: "id, barcode, qty are required" });
      return true;
    }

    const productName = asString(body.product_name) ?? "Unknown";
    const orderId = asString(body.order_id);
    const orderItemId = asString(body.order_item_id);
    const flagged = asBool(body.flagged);
    const scannedAt = isoOrNow(body.scanned_at);

    const result = await insertReceipt({
      id,
      siteId: auth.siteId,
      orderId,
      orderItemId,
      barcode,
      productName,
      qty,
      flagged,
      deviceId: auth.deviceId,
      guardId: auth.guardId,
      scannedAt,
    });

    // Only mutate downstream state on the first successful insert.
    // Retries land here too (id is idempotent) but must be no-ops.
    if (result.inserted) {
      if (orderItemId) {
        await addReceivedQty(orderItemId, qty);
      }
      const existing = await findProduct(auth.siteId, barcode);
      await adjustOnHand({
        siteId: auth.siteId,
        barcode,
        delta: qty,
        fallbackName: productName,
        fallbackCategory: existing?.category ?? null,
        fallbackUnit: existing?.unit ?? null,
      });
    }

    json(res, 200, { id, inserted: result.inserted });
    return true;
  }

  if (pathname === "/api/inventory/products" && method === "POST") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    const body = await readBodyJson(req);
    const barcode = asString(body.barcode);
    const name = asString(body.name);
    if (!barcode || !name) {
      json(res, 400, { error: "barcode and name are required" });
      return true;
    }

    await upsertProduct({
      siteId: auth.siteId,
      barcode,
      name,
      category: asString(body.category),
      unit: asString(body.unit),
      registeredBy: auth.guardName,
    });

    // Seed a zero-quantity stock row so the new SKU appears on the
    // Stock screen immediately, even before any receipts arrive.
    await upsertStock({
      siteId: auth.siteId,
      barcode,
      name,
      category: asString(body.category),
      unit: asString(body.unit),
    });

    json(res, 200, { barcode });
    return true;
  }

  if (pathname === "/api/inventory/issues" && method === "POST") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    const body = await readBodyJson(req);
    const id = asString(body.id);
    const barcode = asString(body.barcode);
    const qty = asNumber(body.qty);
    if (!id || !barcode || qty === null) {
      json(res, 400, { error: "id, barcode, qty are required" });
      return true;
    }

    const productName = asString(body.product_name) ?? "Unknown";
    const result = await insertIssue({
      id,
      siteId: auth.siteId,
      barcode,
      productName,
      qty,
      reason: asString(body.reason),
      takenBy: asString(body.taken_by),
      deviceId: auth.deviceId,
      guardId: auth.guardId,
      issuedAt: isoOrNow(body.issued_at),
    });

    if (result.inserted) {
      await adjustOnHand({
        siteId: auth.siteId,
        barcode,
        delta: -qty,
        fallbackName: productName,
      });
    }

    json(res, 200, { id, inserted: result.inserted });
    return true;
  }

  if (pathname === "/api/inventory/reorder-requests" && method === "POST") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    const body = await readBodyJson(req);
    const id = asString(body.id);
    const barcode = asString(body.barcode);
    if (!id || !barcode) {
      json(res, 400, { error: "id and barcode are required" });
      return true;
    }

    const result = await insertReorderRequest({
      id,
      siteId: auth.siteId,
      barcode,
      productName: asString(body.product_name) ?? "Unknown",
      onHand: asNumber(body.on_hand),
      threshold: asNumber(body.threshold),
      requestedBy: auth.guardName,
      deviceId: auth.deviceId,
      guardId: auth.guardId,
      requestedAt: isoOrNow(body.requested_at),
    });

    json(res, 200, { id, inserted: result.inserted });
    return true;
  }

  if (pathname === "/api/inventory/mismatch-flags" && method === "POST") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    const body = await readBodyJson(req);
    const id = asString(body.id);
    const barcode = asString(body.barcode);
    if (!id || !barcode) {
      json(res, 400, { error: "id and barcode are required" });
      return true;
    }

    const result = await insertMismatchFlag({
      id,
      siteId: auth.siteId,
      receiptId: asString(body.receipt_id),
      orderItemId: asString(body.order_item_id),
      barcode,
      expected: asNumber(body.expected),
      receivedTotal: asNumber(body.received_total),
      note: asString(body.note),
      deviceId: auth.deviceId,
      guardId: auth.guardId,
      flaggedAt: isoOrNow(body.flagged_at),
    });

    json(res, 200, { id, inserted: result.inserted });
    return true;
  }

  // ── Reads ─────────────────────────────────────────────────

  if (pathname === "/api/inventory/orders" && method === "GET") {
    const auth = await authenticate(req, res);
    if (!auth) return true;

    const orders = await listOpenOrders(auth.siteId);
    const items = await Promise.all(orders.map((o) => getOrderItems(o.id)));
    const enriched = orders.map((o, i) => ({ ...o, items: items[i] }));
    json(res, 200, { orders: enriched });
    return true;
  }

  if (pathname === "/api/inventory/stock" && method === "GET") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    json(res, 200, { stock: await listStock(auth.siteId) });
    return true;
  }

  if (pathname === "/api/inventory/alerts" && method === "GET") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    json(res, 200, { alerts: await listLowOrOut(auth.siteId) });
    return true;
  }

  if (pathname.startsWith("/api/inventory/catalog/") && method === "GET") {
    const auth = await authenticate(req, res);
    if (!auth) return true;
    const barcode = decodeURIComponent(pathname.replace("/api/inventory/catalog/", ""));
    const product = await findProduct(auth.siteId, barcode);
    if (!product) {
      // Look ahead at open orders so the field-app can pre-fill the
      // receiving screen even for never-mapped barcodes.
      const openItem = await findOpenItemByBarcode(auth.siteId, barcode);
      json(res, 200, { product: null, openOrderItem: openItem });
      return true;
    }
    const openItem = await findOpenItemByBarcode(auth.siteId, barcode);
    json(res, 200, { product, openOrderItem: openItem });
    return true;
  }

  return false;
}

