          <Text variant="labelLarge" color={palette.onSurface}>
            {leadingIcon}
          </Text>
        ) : null}
        <Text
          variant="labelLarge"
          color={selected ? palette.onSecondaryContainer : palette.onSurface}
        >
          {label}
        </Text>
      </View>
    </Pressable>
  );
}

